import{_ as a,o as t,c as i,a0 as s}from"./chunks/framework.Cl79jK2u.js";const g=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md"}'),n={name:"guide/getting-started.md"};function o(r,e,l,d,h,c){return t(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><p>Moxie connects Telegram and Slack to AI coding agents. Messages you send from your phone are dispatched to agent backends — Claude, Codex, Gemini, Pi, or any CLI that <a href="https://github.com/1broseidon/oneagent" target="_blank" rel="noreferrer">oneagent</a> supports — and the response is delivered back to your chat.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li><strong>Go 1.24+</strong> (for <code>go install</code>) or <strong>Homebrew</strong></li><li>At least one agent CLI installed (see <a href="./backends">Backends</a>)</li><li>A Telegram bot token or Slack app credentials</li></ul><h2 id="install" tabindex="-1">Install <a class="header-anchor" href="#install" aria-label="Permalink to &quot;Install&quot;">​</a></h2><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-k0YGe" id="tab-dZGou4X" checked><label data-title="Homebrew" for="tab-dZGou4X">Homebrew</label><input type="radio" name="group-k0YGe" id="tab-q6eEV1H"><label data-title="Go" for="tab-q6eEV1H">Go</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 1broseidon/tap/moxie</span></span></code></pre></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> github.com/1broseidon/moxie/cmd/moxie@latest</span></span></code></pre></div></div></div><h2 id="configure" tabindex="-1">Configure <a class="header-anchor" href="#configure" aria-label="Permalink to &quot;Configure&quot;">​</a></h2><p>The fastest path is Telegram — two values and you&#39;re running.</p><h3 id="_1-create-a-telegram-bot" tabindex="-1">1. Create a Telegram bot <a class="header-anchor" href="#_1-create-a-telegram-bot" aria-label="Permalink to &quot;1. Create a Telegram bot&quot;">​</a></h3><p>Open <a href="https://t.me/BotFather" target="_blank" rel="noreferrer">BotFather</a> in Telegram and send <code>/newbot</code>. Give it a name and a username ending in <code>bot</code>. Copy the token it returns.</p><h3 id="_2-get-your-chat-id" tabindex="-1">2. Get your chat ID <a class="header-anchor" href="#_2-get-your-chat-id" aria-label="Permalink to &quot;2. Get your chat ID&quot;">​</a></h3><p>Send any message to your new bot, then open this URL in a browser (replace <code>&lt;TOKEN&gt;</code> with your bot token):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://api.telegram.org/bot&lt;TOKEN&gt;/getUpdates</span></span></code></pre></div><p>Find <code>&quot;chat&quot;:{&quot;id&quot;:123456}</code> in the JSON response. That number is your chat ID.</p><h3 id="_3-run-init" tabindex="-1">3. Run init <a class="header-anchor" href="#_3-run-init" aria-label="Permalink to &quot;3. Run init&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span></span></code></pre></div><p>Paste your bot token and chat ID when prompted. This creates <code>~/.config/moxie/config.json</code>.</p><h3 id="_4-start-the-service" tabindex="-1">4. Start the service <a class="header-anchor" href="#_4-start-the-service" aria-label="Permalink to &quot;4. Start the service&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span></span></code></pre></div><p>Send a message to your bot in Telegram. Moxie dispatches it to the default backend (Claude) and replies with the result.</p><h2 id="what-s-happening" tabindex="-1">What&#39;s happening <a class="header-anchor" href="#what-s-happening" aria-label="Permalink to &quot;What&#39;s happening&quot;">​</a></h2><p>When you send a message:</p><ol><li>Moxie receives it via the Telegram or Slack transport</li><li>The message is dispatched to the configured agent backend (e.g. <code>claude -p &quot;your message&quot;</code>)</li><li>The agent works in the configured working directory</li><li>The response is delivered back to your chat</li></ol><p>While the agent is working, you&#39;ll see a typing indicator and activity updates (tool calls, file reads, etc.) as status messages.</p><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><a href="./slack">Set up Slack</a> as an additional or alternative transport</li><li><a href="./backends">Configure backends</a> — switch agents, set default models</li><li><a href="./schedules">Schedule tasks</a> — recurring dispatches, timed reminders</li><li><a href="./commands">Chat commands</a> — <code>/model</code>, <code>/think</code>, <code>/cwd</code>, <code>/new</code></li></ul>',26)])])}const u=a(n,[["render",o]]);export{g as __pageData,u as default};
